def search(arr, target):
    for i in range(len(arr)):
        if arr[i] == target:
            return i
    return -1

data = [12, 45, 7, 23, 56, 89]
print(search(data, 23))

def binary_search(arr, target):
    lo, hi = 0, len(arr) - 1
    while lo <= hi:
        mid = (lo + hi) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            lo = mid + 1
        else:
            hi = mid - 1
    return -1

data = [2, 4, 6, 8, 10, 12, 14]
print(binary_search(data, 10))
